steps.body:
POST envia dados para criar algo.

Você precisa:
- method: 'POST'
- headers: { 'Content-Type': 'application/json' }
- body: JSON.stringify(obj)

Exemplo:

await fetch(url, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ title: 'Nova tarefa', completed: false })
});

DELETE normalmente não precisa de body.

Exemplo:

await fetch(url + '/1', {
  method: 'DELETE'
});

A resposta pode ser:
- 200/204 (ok)

Sempre cheque res.ok.

Para não repetir toda hora, faça um helper:

async function requestJSON(url, options = {}) {
  const res = await fetch(url, options);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);

  // algumas APIs respondem 204 sem body
  const text = await res.text();
  return text ? JSON.parse(text) : null;
}

Isso te dá:
- tratamento de erro
- parse seguro

Depois você usa para POST/PUT/DELETE.

extra.modelJs:
/* Aula 32 — modelJs: POST/PUT/PATCH/DELETE com helper */

async function requestJSON(url, options = {}) {
  const res = await fetch(url, options);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);

  // pode ser 204 (sem body)
  const text = await res.text();
  return text ? JSON.parse(text) : null;
}

const base = 'https://jsonplaceholder.typicode.com/posts';

async function demoCRUD() {
  try {
    // POST
    const criado = await requestJSON(base, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title: 'Meu post', body: 'Olá', userId: 1 })
    });
    console.log('criado:', criado);

    // PUT
    const put = await requestJSON(base + '/1', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: 1, title: 'Atualizado', body: 'Novo', userId: 1 })
    });
    console.log('put:', put);

    // PATCH
    const patch = await requestJSON(base + '/1', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title: 'Só título' })
    });
    console.log('patch:', patch);

    // DELETE
    const del = await requestJSON(base + '/1', { method: 'DELETE' });
    console.log('delete:', del); // pode ser null

  } catch (err) {
    console.error('erro:', err.message);
  }
}

demoCRUD();
